import React, { useState } from 'react';
import Layout from './components/Layout';
import Login from './pages/Login';

function App() {
  // Por ahora, pongamos el token en true para saltar el login y ver la interfaz
  const [token, setToken] = useState(true); 

  if (!token) {
    return <Login onLogin={setToken} />;
  }

  return (
    <Layout>
      <div className="mt-6">
        <h1 className="text-4xl font-bold mb-4">Buenas tardes</h1>
        <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
          {/* Tarjetas de ejemplo */}
          <div className="bg-white/10 p-4 rounded-md hover:bg-white/20 transition cursor-pointer flex items-center gap-4">
            <div className="w-12 h-12 bg-green-500 shadow-lg"></div>
            <span className="font-bold">Mis canciones favoritas</span>
          </div>
          <div className="bg-white/10 p-4 rounded-md hover:bg-white/20 transition cursor-pointer flex items-center gap-4">
            <div className="w-12 h-12 bg-blue-500 shadow-lg"></div>
            <span className="font-bold">Lo-Fi Beats</span>
          </div>
        </div>
      </div>
    </Layout>
  );
}

export default App;
